// ============================================================
// WF-08: SELECTOR DE TURNOS WEB — Premium UI
// ============================================================

const helpers = this.helpers;
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
const WA_TOKEN = $env.META_WHATSAPP_TOKEN;
const PHONE_ID = '963190063548521';
const CONSULTORIO_WA_NUMBER = '5491137936325';
const WA_DEEPLINK = `https://wa.me/${CONSULTORIO_WA_NUMBER}`;

const CONSULTORIO = {
  nombre: 'Policonsultorio Rivadavia',
  direccion: 'Av. Rivadavia 4520, Piso 1, Caballito, CABA',
  mapsLink: 'https://maps.google.com/?q=Av+Rivadavia+4520+CABA'
};
const DIAS = ['Dom','Lun','Mar','Mié','Jue','Vie','Sáb'];
const MESES = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];
const MC = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'];
function argDate(d) { return new Date(d.getTime() - 3*60*60*1000); }

async function supaGet(t, p) { try { return await helpers.httpRequest({ method: 'GET', url: `${SUPABASE_URL}/rest/v1/${t}`, qs: p||{}, headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` } }); } catch(e) { return []; } }
async function supaInsert(t, d) { try { return await helpers.httpRequest({ method: 'POST', url: `${SUPABASE_URL}/rest/v1/${t}`, headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=representation' }, body: JSON.stringify(d) }); } catch(e) { return []; } }
async function supaUpdate(t, f, d) { try { await helpers.httpRequest({ method: 'PATCH', url: `${SUPABASE_URL}/rest/v1/${t}`, qs: f, headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json' }, body: JSON.stringify({ ...d, updated_at: new Date().toISOString() }) }); } catch(e) {} }
async function sendText(ph, tx) { try { await helpers.httpRequest({ method: 'POST', url: `https://graph.facebook.com/v21.0/${PHONE_ID}/messages`, headers: { 'Authorization': `Bearer ${WA_TOKEN}`, 'Content-Type': 'application/json' }, body: JSON.stringify({ messaging_product: 'whatsapp', to: ph, type: 'text', text: { body: tx } }) }); } catch(e) {} }
async function sendCTAUrl(ph, bodyTx, btnText, url) { try { await helpers.httpRequest({ method: 'POST', url: `https://graph.facebook.com/v21.0/${PHONE_ID}/messages`, headers: { 'Authorization': `Bearer ${WA_TOKEN}`, 'Content-Type': 'application/json' }, body: JSON.stringify({ messaging_product: 'whatsapp', to: ph, type: 'interactive', interactive: { type: 'cta_url', body: { text: bodyTx }, action: { name: 'cta_url', parameters: { display_text: btnText, url } } } }) }); } catch(e) {} }

const sessionToken = $input.first().json?.query?.token || '';
const action = $input.first().json?.query?.action || '';
const slotParam = $input.first().json?.query?.slot || '';
const host = $input.first().json?.headers?.host || '';
const baseUrl = `https://${host}/webhook/consultorio-turnos`;

function errPg(title, msg, type) {
  const cl = {error:{bg:'#FEE2E2',c:'#EF4444'},expired:{bg:'#FEF3C7',c:'#F59E0B'},empty:{bg:'#DBEAFE',c:'#2563EB'}};
  const cc = cl[type]||cl.error;
  const ic = {error:'<circle cx="12" cy="12" r="10"/><line x1="15" y1="9" x2="9" y2="15"/><line x1="9" y1="9" x2="15" y2="15"/>',expired:'<circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/>',empty:'<rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/>'};
  return `<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>${title}</title><style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:system-ui,sans-serif;background:#F0F4FF;min-height:100dvh;display:flex;justify-content:center;align-items:center;padding:32px}.c{text-align:center;max-width:320px}.i{width:80px;height:80px;border-radius:50%;background:${cc.bg};display:flex;align-items:center;justify-content:center;margin:0 auto 20px}.i svg{width:36px;height:36px;color:${cc.c}}h2{font-size:20px;font-weight:700;color:#1E293B;margin-bottom:8px}p{font-size:15px;color:#64748B;line-height:1.5}</style></head><body><div class="c"><div class="i"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">${ic[type]||ic.error}</svg></div><h2>${title}</h2><p>${msg}</p></div></body></html>`;
}

function sucPg(prof, fecha, hora) {
  return `<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><meta name="theme-color" content="#10B981"><title>Turno Confirmado</title><style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:system-ui,sans-serif;background:#F0F4FF;min-height:100dvh;display:flex;justify-content:center}.a{max-width:480px;width:100%;display:flex;flex-direction:column;align-items:center;padding:60px 24px 40px;text-align:center}.sc{width:96px;height:96px;border-radius:50%;background:linear-gradient(135deg,#10B981,#34D399);display:flex;align-items:center;justify-content:center;margin-bottom:24px;box-shadow:0 8px 32px rgba(16,185,129,0.3);animation:pop 0.5s cubic-bezier(0.34,1.56,0.64,1) forwards;opacity:0;transform:scale(0.3)}@keyframes pop{to{opacity:1;transform:scale(1)}}.sc svg{width:44px;height:44px;color:#fff}h2{font-size:24px;font-weight:700;color:#1E293B;margin-bottom:8px;animation:fu 0.5s 0.2s ease forwards;opacity:0;transform:translateY(12px)}.sub{font-size:15px;color:#64748B;margin-bottom:28px;animation:fu 0.5s 0.3s ease forwards;opacity:0;transform:translateY(12px)}@keyframes fu{to{opacity:1;transform:translateY(0)}}.cd{background:#fff;border-radius:16px;padding:20px;width:100%;box-shadow:0 8px 32px rgba(37,99,235,0.12);animation:fu 0.5s 0.4s ease forwards;opacity:0;transform:translateY(12px)}.rw{display:flex;align-items:center;gap:12px;padding:10px 0}.rw+.rw{border-top:1px solid #E2E8F0}.ri{display:flex;align-items:center;justify-content:center;width:36px;height:36px;border-radius:10px;background:#DBEAFE;flex-shrink:0}.ri svg{width:18px;height:18px;color:#2563EB}.rl{font-size:11px;font-weight:600;color:#94A3B8;text-transform:uppercase;letter-spacing:0.05em}.rv{font-size:15px;font-weight:500;color:#1E293B}.wa{display:flex;align-items:center;gap:8px;margin-top:24px;padding:14px 20px;border-radius:100px;background:#D1FAE5;color:#065F46;font-size:14px;font-weight:500;animation:fu 0.5s 0.6s ease forwards;opacity:0;transform:translateY(12px)}.wa svg{width:20px;height:20px;flex-shrink:0}.cl{margin-top:20px;font-size:13px;color:#94A3B8;animation:fu 0.5s 0.7s ease forwards;opacity:0}.back-wa{display:flex;align-items:center;justify-content:center;gap:10px;margin-top:24px;padding:16px 24px;background:#25D366;color:#fff;text-decoration:none;font-weight:600;font-size:16px;border-radius:100px;box-shadow:0 8px 24px rgba(37,211,102,0.3);min-height:52px;transition:transform 0.2s}.back-wa:active{transform:scale(0.97)}.back-wa svg{width:22px;height:22px}.countdown{margin-top:14px;font-size:13px;color:#64748B;text-align:center}</style></head><body><div class="a"><div class="sc"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg></div><h2>\u00a1Turno confirmado!</h2><p class="sub">Tu turno fue reservado exitosamente</p><div class="cd"><div class="rw"><div class="ri"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/></svg></div><div><div class="rl">Profesional</div><div class="rv">${prof.nombre} \u2014 ${prof.especialidad}</div></div></div><div class="rw"><div class="ri"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg></div><div><div class="rl">Fecha y hora</div><div class="rv">${fecha}, ${hora} hs</div></div></div><div class="rw"><div class="ri"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"/><circle cx="12" cy="10" r="3"/></svg></div><div><div class="rl">Consultorio</div><div class="rv">${prof.consultorio}, Piso 1</div></div></div></div><div class="wa"><svg viewBox="0 0 24 24" fill="currentColor"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413z"/></svg>Te enviamos la confirmaci\u00f3n por WhatsApp</div><a href="${WA_DEEPLINK}" class="back-wa"><svg viewBox="0 0 24 24" fill="currentColor"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413z"/></svg>Volver a WhatsApp</a><p class="countdown" id="cd">Volviendo en <span id="cd-n">3</span> segundos...</p><script>(function(){var n=3;var el=document.getElementById('cd-n');var iv=setInterval(function(){n--;if(el)el.textContent=n;if(n<=0){clearInterval(iv);location.href='${WA_DEEPLINK}';}},1000);})();</script></div></body></html>`;
}

if (!sessionToken) return [{json:{html:errPg('Link inv\u00e1lido','Este link no es v\u00e1lido.','error')}}];

const allC = await supaGet('consultorio_conversaciones',{select:'*'});
const conv = allC?.find(c => c.contexto?.bookingToken === sessionToken);
if (!conv||!conv.contexto) return [{json:{html:errPg('Sesi\u00f3n expirada','Este enlace ya no es v\u00e1lido. Escrib\u00ed por WhatsApp para uno nuevo.','expired')}}];

const ctx = conv.contexto;
const profs = await supaGet('consultorio_profesionales',{id:`eq.${ctx.profesionalId}`,select:'nombre,especialidad,consultorio,duracion_turno_min'});
const prof = profs?.[0];
if (!prof) return [{json:{html:errPg('Error','No se pudo cargar el profesional.','error')}}];

// === CONFIRMAR ===
if (action === 'confirmar' && slotParam) {
  const slotIso = decodeURIComponent(slotParam);
  await supaInsert('consultorio_turnos',{paciente_id:ctx.pacienteId,profesional_id:ctx.profesionalId,fecha_hora:slotIso,estado:'agendado',tipo_pago:ctx.obraSocial?'obra_social':'particular'});
  await supaUpdate('consultorio_conversaciones',{telefono_wa:`eq.${conv.telefono_wa}`},{estado:'inicio',contexto:{}});
  const d = argDate(new Date(slotIso));
  const fec = `${DIAS[d.getUTCDay()]} ${d.getUTCDate()} de ${MESES[d.getUTCMonth()]}`;
  const hr = `${String(d.getUTCHours()).padStart(2,'0')}:${String(d.getUTCMinutes()).padStart(2,'0')}`;
  let msg = `\u2705 *TURNO CONFIRMADO*\n\n\ud83d\udcc5 ${fec}, ${hr} hs\n\ud83d\udc68\u200d\u2695\ufe0f ${prof.nombre} \u2014 ${prof.especialidad}\n\ud83d\udccd ${CONSULTORIO.direccion}, ${prof.consultorio}\n\ud83d\uddfa\ufe0f ${CONSULTORIO.mapsLink}\n\nRecord\u00e1 traer:\n\u2022 DNI\n`;
  if (ctx.obraSocial) msg += `\u2022 Credencial de ${ctx.obraSocial}\n`;
  msg += `\nTe voy a mandar un recordatorio. Para cancelar o reprogramar, escribime. \ud83d\udc4b`;
  const turDur = prof.duracion_turno_min || 15;
  const p2 = (n) => String(n).padStart(2, '0');
  const gcStart = `${d.getUTCFullYear()}${p2(d.getUTCMonth()+1)}${p2(d.getUTCDate())}T${p2(d.getUTCHours())}${p2(d.getUTCMinutes())}00`;
  const gcEndD = new Date(d.getTime() + turDur * 60 * 1000);
  const gcEnd = `${gcEndD.getUTCFullYear()}${p2(gcEndD.getUTCMonth()+1)}${p2(gcEndD.getUTCDate())}T${p2(gcEndD.getUTCHours())}${p2(gcEndD.getUTCMinutes())}00`;
  const gcalUrl = `https://calendar.google.com/calendar/render?action=TEMPLATE&text=${encodeURIComponent('Turno: ' + prof.nombre)}&dates=${gcStart}/${gcEnd}&details=${encodeURIComponent('Turno con ' + prof.nombre + ' (' + prof.especialidad + ')')}&location=${encodeURIComponent(CONSULTORIO.direccion)}`;
  await sendCTAUrl(conv.telefono_wa, msg, 'Google Calendar', gcalUrl);
  return [{json:{html:sucPg(prof,fec,hr)}}];
}

// === GENERAR SLOTS ===
const hor = await supaGet('consultorio_horarios_profesional',{profesional_id:`eq.${ctx.profesionalId}`,select:'dia_semana,hora_inicio,hora_fin'});
const dur = prof.duracion_turno_min||15;
const nowA = argDate(new Date());
const tns = await supaGet('consultorio_turnos',{profesional_id:`eq.${ctx.profesionalId}`,select:'fecha_hora',estado:'not.in.(cancelado,auto_cancelado)'});
const tk = new Set();
if(tns) for(const t of tns){const a=argDate(new Date(t.fecha_hora));tk.add(`${a.getUTCFullYear()}-${String(a.getUTCMonth()+1).padStart(2,'0')}-${String(a.getUTCDate()).padStart(2,'0')}T${String(a.getUTCHours()).padStart(2,'0')}:${String(a.getUTCMinutes()).padStart(2,'0')}`)}
const sbd = {};
for(let dd=0;dd<14;dd++){const dt=new Date(nowA.getTime()+dd*24*60*60*1000);let jd=dt.getUTCDay();let db=jd===0?7:jd;const sc=hor.filter(h=>h.dia_semana===db);if(!sc.length)continue;const ds=`${dt.getUTCFullYear()}-${String(dt.getUTCMonth()+1).padStart(2,'0')}-${String(dt.getUTCDate()).padStart(2,'0')}`;sbd[ds]={dayName:DIAS[jd],dayNum:dt.getUTCDate(),month:MC[dt.getUTCMonth()],slots:[]};for(const s of sc){const[sh,sm]=s.hora_inicio.split(':').map(Number);const[eh,em]=s.hora_fin.split(':').map(Number);let h=sh,m=sm;while(h*60+m+dur<=eh*60+em){if(dd===0){const nw=nowA.getUTCHours()*60+nowA.getUTCMinutes();if(h*60+m<=nw){m+=dur;if(m>=60){h++;m-=60}continue}}const ts=`${String(h).padStart(2,'0')}:${String(m).padStart(2,'0')}`;if(!tk.has(`${ds}T${ts}`))sbd[ds].slots.push({time:ts,iso:`${ds}T${ts}:00-03:00`,franja:h<12?'AM':'PM'});m+=dur;if(m>=60){h++;m-=60}}}if(sbd[ds].slots.length===0)delete sbd[ds]}
const dates = Object.keys(sbd);
if(!dates.length) return [{json:{html:errPg('Sin turnos',`No hay horarios con ${prof.nombre} en los pr\u00f3ximos 14 d\u00edas.`,'empty')}}];

const pi = ctx.obraSocial ? `${ctx.obraSocial} \u2014 el copago se abona al llegar en recepci\u00f3n` : 'Particular \u2014 $45.000 se abona al llegar en recepci\u00f3n';
const ini = prof.nombre.split(' ').filter(w=>w.length>1&&w[0]===w[0].toUpperCase()).map(w=>w[0]).join('').substring(0,2)||'DR';
