const html = `<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1,maximum-scale=1,user-scalable=no"><meta name="theme-color" content="#2563EB"><title>Turnos - ${CONSULTORIO.nombre}</title><style>*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}:root{--p:#2563EB;--pl:#DBEAFE;--a:#8B5CF6;--ok:#10B981;--bg:#F0F4FF;--c:#FFF;--t:#1E293B;--ts:#64748B;--tm:#94A3B8;--b:#E2E8F0;--r:#EF4444}body{font-family:system-ui,-apple-system,sans-serif;background:var(--bg);color:var(--t);min-height:100dvh;-webkit-font-smoothing:antialiased}.app{max-width:480px;margin:0 auto;min-height:100dvh;background:var(--bg)}.hdr{background:linear-gradient(135deg,var(--p),var(--a));padding:24px 20px 28px;color:#fff;position:relative;overflow:hidden}.hdr::before{content:'';position:absolute;top:-40%;right:-20%;width:200px;height:200px;border-radius:50%;background:rgba(255,255,255,0.08)}.hdr::after{content:'';position:absolute;bottom:-30%;left:-10%;width:150px;height:150px;border-radius:50%;background:rgba(255,255,255,0.05)}.hdr>div{position:relative;z-index:1}.hdr h1{font-size:20px;font-weight:700}.hdr p{font-size:14px;opacity:0.85;margin-top:4px}.pc{background:var(--c);margin:-12px 16px 0;border-radius:16px;padding:16px;display:flex;align-items:center;gap:14px;position:relative;z-index:2;box-shadow:0 8px 32px rgba(37,99,235,0.12)}.pa{width:52px;height:52px;border-radius:50%;background:linear-gradient(135deg,var(--p),var(--a));display:flex;align-items:center;justify-content:center;color:#fff;font-size:18px;font-weight:700;flex-shrink:0}.pn{font-size:16px;font-weight:600;display:flex;align-items:center;gap:6px}.vb{display:inline-flex;align-items:center;justify-content:center;width:18px;height:18px;border-radius:50%;background:var(--p)}.pe{font-size:13px;color:var(--ts);font-weight:500}.pr{font-size:12px;color:var(--tm)}.sec{padding:20px 16px 0}.sl{font-size:13px;font-weight:600;color:var(--ts);text-transform:uppercas